const results = [];

for (const item of $input.all()) {
  const j = item.json;

  const url = (j.jobUrl || j.url || j.link || '').trim();
  const title = j.title || j.jobTitle || j.position || '';
  const company = j.company || j.companyName || '';
  const location = j.location || j.jobLocation || '';
  const description = j.description || j.jobDescription || j.descriptionHtml || '';

  if (!url || !title || !description || description.length < 100) {
    continue;
  }

  results.push({
    json: {
      url,
      title,
      company,
      location,
      description
    }
  });
}

console.log(`Jobs after normalization: ${results.length}`);
return results;

const results = [];

const HIGH_PATTERNS = [
  /visa sponsorship/i,
  /visa sponsor/i,
  /sponsorship available/i,
  /work permit sponsorship/i,
  /relocation support/i,
  /relocation package/i,
  /we sponsor/i,
  /sponsor your visa/i,
  /global mobility/i,
  /kennismigrant/i,
  /highly skilled migrant/i,
  /ind sponsor/i,
  /immigration support/i
];

const REJECTION_PATTERNS = [
  /must already have work authorization/i,
  /must be authorized to work/i,
  /no sponsorship/i,
  /cannot sponsor/i,
  /without sponsorship/i,
  /eu citizenship required/i,
  /eu passport required/i,
  /netherlands only/i,
  /dutch speakers only/i,
  /must speak dutch/i,
  /visa not provided/i,
  /sponsorship not available/i
];

for (const item of $input.all()) {
  const job = item.json;

  const text = `\n${job.title || ''}\n${job.company || ''}\n${job.description || ''}\n`.toLowerCase();

  const matchedHigh = HIGH_PATTERNS
    .filter(r => r.test(text))
    .map(r => r.source);

  const matchedReject = REJECTION_PATTERNS
    .filter(r => r.test(text))
    .map(r => r.source);

  if (matchedReject.length > 0) continue;
  if (matchedHigh.length === 0) continue;

  results.push({
    json: {
      ...job,
      relocation_signals: matchedHigh.join(', '),
      relocation_confidence: 'high'
    }
  });
}

console.log(`Jobs after relocation filter: ${results.length}`);
return results;

// $input.all() = new filtered jobs from Apify (passed through from input1 of Merge)
// $('Get Existing Jobs').all() = all rows already in the Google Sheet

const normalizeUrl = (url = '') =>
  url.toString().split('?')[0].replace(/\/$/, '').trim().toLowerCase();

const normalizeText = (v = '') =>
  v.toString().trim().toLowerCase();

// Build a set of keys from the existing sheet rows
const existing = new Set();

let sheetRows = [];
try {
  sheetRows = $('Get Existing Jobs').all();
} catch (e) {
  sheetRows = [];
}

for (const row of sheetRows) {
  const r = row.json || {};
  const url = r.URL || r.Url || r.url || '';
  if (!url) continue;
  const key = [
    normalizeUrl(url),
    normalizeText(r.Company || r.company || ''),
    normalizeText(r.Role || r.role || '')
  ].join('|');
  existing.add(key);
}

console.log(`Existing sheet rows loaded: ${existing.size}`);

// Now check each incoming new job against the existing set
const output = [];

for (const item of $input.all()) {
  const job = item.json || {};

  if (!job.url || !job.title) continue;

  const key = [
    normalizeUrl(job.url),
    normalizeText(job.company || ''),
    normalizeText(job.title)
  ].join('|');

  if (existing.has(key)) {
    console.log(`Duplicate skipped: ${job.title} @ ${job.company}`);
    continue;
  }

  output.push({ json: job });
}

console.log(`New unique jobs after dedup: ${output.length}`);
return output;

const results = [];

const coverLetterTemplate = `Dear Hiring Manager,

I am excited to apply for the [JOB_TITLE] position at [COMPANY_NAME].

I am currently working as a Senior Software Engineer (SDE3 / Associate Vice President) at JPMorgan Chase Asset & Wealth Management, where I work on AI-native engineering platforms, MCP server infrastructure, developer tooling, and cloud systems.

I work extensively with React, TypeScript, Python, AWS, AI tooling, and scalable engineering systems.

I am particularly interested in relocating to the Netherlands through a visa sponsorship / kennismigrant opportunity.

Thank you for your consideration.

Best regards,
Shirsak Sahoo`;

for (const item of $input.all()) {
  const {
    url,
    title,
    company,
    location,
    description,
    relocation_signals,
    relocation_confidence
  } = item.json;

  const trimmedDescription = description.substring(0, 1800);

  const payload = {
    model: 'unsloth/Qwen3.5-9B-GGUF:Q6_K',
    temperature: 0.4,
    max_tokens: 10000,
    top_p: 0.9,
    repeat_penalty: 1.1,
    stop: ['<|im_end|>', '</s>'],
    messages: [
      {
        role: 'system',
        content: 'You are an expert cover letter writer. Generate concise professional cover letters tailored to the role.'
      },
      {
        role: 'user',
        content: `Template:\n${coverLetterTemplate}\n\nJob Description:\n${trimmedDescription}\n\nCompany: ${company}\nRole: ${title}\nLocation: ${location}\n\nGenerate a personalized cover letter.`
      }
    ],
    extra_body: {
      chat_template_kwargs: {
        enable_thinking: false
      }
    }
  };

  results.push({
    json: {
      _job: {
        url,
        title,
        company,
        location,
        description: trimmedDescription,
        relocation_signals,
        relocation_confidence
      },
      _llmPayload: payload
    }
  });
}

return results;

const llmItem = $input.first();
const reqItem = $('Build Cover Letter Request').first();

if (!llmItem?.json || !reqItem?.json?._job) {
  return [];
}

const coverLetter = (llmItem.json?.choices?.[0]?.message?.content || '').trim();

if (!coverLetter) {
  return [];
}

const job = reqItem.json._job;

return [
  {
    json: {
      date: new Date().toISOString().split('T')[0],
      company: job.company || '',
      title: job.title || '',
      location: job.location || '',
      url: job.url || '',
      relocation_signals: job.relocation_signals || '',
      relocation_confidence: job.relocation_confidence || '',
      cover_letter: coverLetter,
      status: 'Not Applied'
    }
  }
];
